// AUTO-GENERATED by runs/_generate.mjs — standalone runner for Chromes.download.
// Edit the method in utils/Chromes.js, then re-run the generator to refresh.
// Calls Chromes.download(...) directly; no shared engine.
//
// argv[1] is repointed at a phantom entrypoint in the PROJECT ROOT *before* the
// dynamic imports run, because utils/Secrets.js loads .env (and Yamls reads
// config.yml) from dirname(process.argv[1]). runs/Chromes/ is two levels
// below root, so '..','..' = root.
import path from 'node:path';
process.argv[1] = path.resolve(import.meta.dirname, '..', '..', 'runner.js');

const yargsMod = await import('yargs');
const { hideBin } = await import('yargs/helpers');
const yargs = yargsMod.default;
const { Chromes } = await import('../../utils/Chromes.js');
const { Yamls } = await import('../../utils/Yamls.js');
const { Dates } = await import('../../utils/Dates.js');
const { Dialogs } = await import('../../utils/Dialogs.js');

async function main() {
    console.log('1️⃣ Chromes download Start');

    const argv = yargs(hideBin(process.argv))
        .option("url", { describe: "url" })
        .option("options", { describe: "options" })
        .option("owner", { describe: "owner" })
        .option("fileType", { describe: "fileType" })
        .option("duration", { describe: "duration (optional)" })
        .option("replace", { describe: "replace (optional)" })
        .help()
        .parse();

    const run = async () => {
        const result = await Chromes.download(argv["url"], argv["options"], argv["owner"], argv["fileType"], argv["duration"], argv["replace"]);
        if (result !== undefined) console.log('📤 Result:', typeof result === 'object' ? JSON.stringify(result, null, 2) : result);
    };

    if (Yamls.getConfig('CmdLine.TryCatch') === 'true') {
        try {
            await run();
            Dates.sleep(Number(Yamls.getConfig('CmdLine.ExitTimeout')));
        } catch (error) {
            console.error('❌ Error:', error);
            Dialogs.warningBox(error.message, 'Chromes download Error');
            Dates.sleep(Number(Yamls.getConfig('CmdLine.ExitTimeoutError')));
            process.exit(1);
        }
    } else {
        await run();
        Dates.sleep(Number(Yamls.getConfig('CmdLine.ExitTimeout')));
    }

    console.log('3️⃣ Chromes download Done');
}

main();
